mapper.insert:
		/* oms-order-inventoryStatusBatch-sql-oracle.xml - insertIntfIvStatusOmsToWms */
		INSERT INTO TORDER_INTF_WMS_REQORDERIV
		(
			  CTKEY
            , OWKEY
            , ICKEY
            , AVQTY
            , UNUSEQTY
            , REQUESTDT
            , IFID
            , INSERTDATE
            , INSERTURKEY
            , UPDATEDATE
            , UPDATEURKEY
		) VALUES (
	      	  #{ctkey}
            , #{owkey}
            , #{ickey}
            , #{avqty}
            , #{navqty}
            , #{requestdt}
            , #{ifid}
		    , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
		    , #{interfaceUrkey}
		    , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
		    , #{interfaceUrkey}
		)
